-- Dizzy Toad Woodworks — seed the current 22 pieces.
-- Run AFTER schema.sql, in the Supabase SQL Editor. Safe to re-run.

on conflict (id) do update set
  name=excluded.name, category=excluded.category, species=excluded.species,
  dimensions=excluded.dimensions, price=excluded.price, status=excluded.status,
  photos=excluded.photos, description=excluded.description, care=excluded.care, sort=excluded.sort;
